tm.firstKey();           // smallest key
tm.lastKey();            // largest key
tm.headMap("m");         // all entries with key < "m"
tm.tailMap("m");         // all entries with key >= "m"
tm.floorKey("grape");    // greatest key <= "grape"
tm.ceilingKey("grape");  // smallest key >= "grape"
